struct PasswordResetView: View {
    @State private var token: String
    @State private var newPassword = ""
    @State private var confirmPassword = ""
    @State private var message: String?
    @State private var isResetting = false

    init(token: String) {
        _token = State(initialValue: token)
    }

    var body: some View {
        VStack(spacing: 20) {
            Text("Reset Your Password")
                .font(.largeTitle)
                .fontWeight(.bold)

            SecureField("New Password", text: $newPassword)
                .textFieldStyle(RoundedBorderTextFieldStyle())
                .autocapitalization(.none)
                .padding(.horizontal)

            SecureField("Confirm Password", text: $confirmPassword)
                .textFieldStyle(RoundedBorderTextFieldStyle())
                .autocapitalization(.none)
                .padding(.horizontal)

            Button(action: resetPassword) {
                if isResetting {
                    ProgressView()
                } else {
                    Text("Reset Password")
                        .font(.headline)
                        .foregroundColor(.white)
                        .padding()
                        .frame(maxWidth: .infinity)
                        .background(Color.blue)
                        .cornerRadius(10)
                }
            }
            .disabled(newPassword.isEmpty || confirmPassword.isEmpty || newPassword != confirmPassword || isResetting)
            .padding(.horizontal)

            if let message = message {
                Text(message)
                    .foregroundColor(message.contains("Success") ? .green : .red)
                    .padding(.top, 10)
            }

            Spacer()
        }
        .padding()
        .navigationTitle("Password Reset")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            print("PasswordResetView appeared with token: \(token)")
        }
    }

    private func resetPassword() {
        guard newPassword == confirmPassword else {
            message = "Passwords do not match."
            return
        }
        guard !newPassword.isEmpty else {
            message = "Password cannot be empty."
            return
        }

        isResetting = true
        message = nil

        // Simulate API call
        DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
            isResetting = false
            if Bool.random() { // Simulate success or failure
                message = "Success: Your password has been reset."
                // In a real app, you might navigate away or prompt the user to log in
                newPassword = ""
                confirmPassword = ""
            } else {
                message = "Error: Could not reset password. Please try again."
            }
        }
    }
}

enum AppLink: Equatable {
    case passwordReset(token: String)
    case otherLink // For other potential deep links
    case none
}

class AppLinkManager: ObservableObject {
    @Published var appLink: AppLink? {
        didSet {
            // Optional: reset appLink after it has been handled to prevent re-triggering
            // This depends on your navigation logic (e.g., if you pop views or replace root)
            // For example, if you push a view for appLink, you might clear it after the push
            if appLink != nil && appLink != .none {
                print("AppLinkManager received appLink: \(appLink!)")
                // A common pattern is to set it to .none after handling
                // if the destination view doesn't rely on it staying set
                // For a NavigationStack/Path, keeping it set until the view is pushed is fine.
            }
        }
    }

    func handleUniversalLink(_ url: URL) {
        print("Received universal link: \(url.absoluteString)")
        guard url.scheme == "https", url.host == "myapp.com" else {
            print("URL does not match expected scheme or host.")
            appLink = .none
            return
        }

        switch url.path {
        case "/reset-password":
            if let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
               let queryItems = components.queryItems {
                for item in queryItems {
                    if item.name == "token", let token = item.value {
                        print("Found password reset token: \(token)")
                        appLink = .passwordReset(token: token)
                        return
                    }
                }
            }
            print("Password reset link without a token.")
            appLink = .none
        default:
            print("Unknown path for universal link: \(url.path)")
            appLink = .otherLink // Handle other potential deep links here
        }
    }
}

struct ContentView: View {
    @EnvironmentObject var appLinkManager: AppLinkManager
    @State private var path = NavigationPath()

    var body: some View {
        NavigationStack(path: $path) {
            VStack {
                Image(systemName: "globe")
                    .imageScale(.large)
                    .foregroundColor(.accentColor)
                Text("Welcome to My App!")

                Button("Simulate Password Reset Link") {
                    let simulatedURL = URL(string: "https://myapp.com/reset-password?token=mocktoken123")!
                    appLinkManager.handleUniversalLink(simulatedURL)
                }
                .padding()
            }
            .navigationDestination(for: AppLink.self) { link in
                switch link {
                case .passwordReset(let token):
                    PasswordResetView(token: token)
                case .otherLink:
                    Text("You landed on an 'other' deep link!")
                        .navigationTitle("Other Link")
                case .none:
                    Text("No specific deep link action.")
                }
            }
        }
        .onChange(of: appLinkManager.appLink) { newLink in
            if let newLink = newLink, newLink != .none {
                print("ContentView: appLinkManager.appLink changed to \(newLink). Pushing to path.")
                path.append(newLink)
                // Optionally clear the link after handling if you don't want it to persist
                // appLinkManager.appLink = .none
            }
        }
    }
}

@main
struct UniversalLinkApp: App {
    @StateObject var appLinkManager = AppLinkManager()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(appLinkManager)
                .onOpenURL { url in
                    // This is where actual universal links are received
                    appLinkManager.handleUniversalLink(url)
                }
        }
    }
}

